import{_ as o,o as r,c as n,ae as s}from"./chunks/framework.C8MNLDzb.js";const c=JSON.parse('{"title":"集部 · 诗词文赋","description":"","frontmatter":{},"headers":[],"relativePath":"docs/集部/index.md","filePath":"docs/集部/index.md"}'),l={name:"docs/集部/index.md"};function i(a,t,g,e,h,d){return r(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="集部-·-诗词文赋" tabindex="-1">集部 · 诗词文赋 <a class="header-anchor" href="#集部-·-诗词文赋" aria-label="Permalink to &quot;集部 · 诗词文赋&quot;">​</a></h1><blockquote><p>集部收录历代诗词文赋，是中华文学艺术的结晶。诗言志，词缘情，承载文人的志向、情感与审美追求。</p></blockquote><hr><h2 id="唐诗名句" tabindex="-1">唐诗名句 <a class="header-anchor" href="#唐诗名句" aria-label="Permalink to &quot;唐诗名句&quot;">​</a></h2><ol><li><strong>海内存知己，天涯若比邻。</strong> —— 只要世间还有知己，就算远在天涯也像近邻一样。（王勃《送杜少府之任蜀州》）</li><li><strong>落霞与孤鹜齐飞，秋水共长天一色。</strong> —— 落霞与孤雁一同飞翔，秋天的江水和天空连成一片。（王勃《滕王阁序》）</li><li><strong>春江潮水连海平，海上明月共潮生。</strong> —— 春天的江潮水势浩荡与大海连成一片，一轮明月从海上升起，仿佛与潮水一起涌生。（张若虚《春江花月夜》）</li><li><strong>欲穷千里目，更上一层楼。</strong> —— 想看得更远，就要再登上一层楼。（王之涣《登鹳雀楼》）</li><li><strong>黄沙百战穿金甲，不破楼兰终不还。</strong> —— 在沙漠里身经百战，不攻破楼兰城誓不回还。（王昌龄《从军行》）</li><li><strong>但使龙城飞将在，不教胡马度阴山。</strong> —— 假如飞将军李广还在，绝不会让敌人的兵马越过阴山。（王昌龄《出塞》）</li><li><strong>大漠孤烟直，长河落日圆。</strong> —— 广阔沙漠中一缕孤烟直冲云霄，悠长黄河边一轮落日浑圆。（王维《使至塞上》）</li><li><strong>明月松间照，清泉石上流。</strong> —— 明亮的月光洒在松林间，清澈的泉水在石头上流淌。（王维《山居秋暝》）</li><li><strong>独在异乡为异客，每逢佳节倍思亲。</strong> —— 独自在他乡作客，每到美好的节日就更加思念亲人。（王维《九月九日忆山东兄弟》）</li><li><strong>君不见黄河之水天上来，奔流到海不复回。</strong> —— 黄河的水是从天上流下来的，奔向大海一去不回来。（李白《将进酒》）</li><li><strong>天生我材必有用，千金散尽还复来。</strong> —— 上天赋予我的才华必定有用，千两黄金花光了还会再回来。（李白《将进酒》）</li><li><strong>安能摧眉折腰事权贵，使我不得开心颜！</strong> —— 怎么能低眉弯腰去侍奉权贵，让我不能开心地展现笑容！（李白《梦游天姥吟留别》）</li><li><strong>无边落木萧萧下，不尽长江滚滚来。</strong> —— 无边无际的树木落叶萧萧飘下，奔腾不息的长江滚滚而来。（杜甫《登高》）</li><li><strong>国破山河在，城春草木深。感时花溅泪，恨别鸟惊心。</strong> —— 国家破碎了但山河依然存在，感伤时局花也落泪。（杜甫《春望》）</li><li><strong>烽火连三月，家书抵万金。</strong> —— 战争连续三个月不停，一封家信珍贵得抵得万两黄金。（杜甫《春望》）</li><li><strong>会当凌绝顶，一览众山小。</strong> —— 我一定要登上泰山顶峰，俯瞰群山，它们是那么渺小。（杜甫《望岳》）</li><li><strong>朱门酒肉臭，路有冻死骨。</strong> —— 富贵人家美酒佳肴吃不完，门外的路上却有冻饿而死的白骨。（杜甫《自京洛奉先县咏怀五百字》）</li><li><strong>同是天涯沦落人，相逢何必曾相识。</strong> —— 同样是流落在天涯的人，相遇何必曾经相识呢。（白居易《琵琶行》）</li><li><strong>离离原上草，一岁一枯荣。野火烧不尽，春风吹又生。</strong> —— 原野上茂密的青草，一年一度枯萎又繁荣。（白居易《赋得古原草送别》）</li><li><strong>曾经沧海难为水，除却巫山不是云。</strong> —— 曾经见过沧海的水，别处的水就不足为水了。（元稹《离思》）</li><li><strong>春蚕到死丝方尽，蜡炬成灰泪始干。</strong> —— 春蚕直到死才停止吐丝，蜡烛烧成灰后烛泪才停止流淌。比喻对感情至死不渝。（李商隐《无题》）</li><li><strong>身无彩凤双飞翼，心有灵犀一点通。</strong> —— 身上没有彩凤的翅膀，心中却像灵犀一样彼此相通。（李商隐《无题》）</li></ol><hr><h2 id="宋词名句" tabindex="-1">宋词名句 <a class="header-anchor" href="#宋词名句" aria-label="Permalink to &quot;宋词名句&quot;">​</a></h2><ol><li><strong>明月几时有？把酒问青天。</strong> —— 明月什么时候才有？我端起酒杯询问青天。（苏轼《水调歌头》）</li><li><strong>但愿人长久，千里共婵娟。</strong> —— 只希望人能平安健康，即使相隔千里也能共同欣赏这美好的月光。（苏轼《水调歌头》）</li><li><strong>大江东去，浪淘尽，千古风流人物。</strong> —— 大江的水一直向东流去，波浪淘洗尽了千古以来的英雄豪杰。（苏轼《念奴娇·赤壁怀古》）</li><li><strong>人生如梦，一尊还酹江月。</strong> —— 人生不过像一场梦，我举起酒杯洒在江里祭奠那轮明月。（苏轼《念奴娇·赤壁怀古》）</li><li><strong>十年生死两茫茫，不思量，自难忘。</strong> —— 十年来生死相隔，即使不去刻意想念，自然也难以遗忘。（苏轼《江城子》）</li><li><strong>莫听穿林打叶声，何妨吟啸且徐行。</strong> —— 不必在意那穿过树林打在叶子上的雨声，姑且一边吟诗长啸一边慢慢走吧。（苏轼《定风波》）</li><li><strong>竹杖芒鞋轻胜马，谁怕？一蓑烟雨任平生。</strong> —— 拄着竹杖穿着草鞋走路比骑马还轻快，一身蓑衣在风雨中度过一生也任其自然。（苏轼《定风波》）</li><li><strong>莫道不消魂，帘卷西风，人比黄花瘦。</strong> —— 别说不会消磨神魂，西风吹起帘子，人比那秋天的菊花还要消瘦。（李清照《醉花阴》）</li><li><strong>寻寻觅觅，冷冷清清，凄凄惨惨戚戚。</strong> —— 反复地寻求搜索，眼前只有冷冷清清，凄凉悲伤一起涌来。（李清照《声声慢》）</li><li><strong>生当作人杰，死亦为鬼雄。</strong> —— 活着的时候要当人中的豪杰，死了也要做鬼中的英雄。（李清照《夏日绝句》）</li><li><strong>莫等闲、白了少年头，空悲切。</strong> —— 不要虚度光阴，等少年头变白时，只能徒然悲伤。（岳飞《满江红》）</li><li><strong>众里寻他千百度，蓦然回首，那人却在，灯火阑珊处。</strong> —— 在人群中寻找她千百次，突然回头一看，她却站在灯火零落的地方。（辛弃疾《青玉案·元夕》）</li><li><strong>醉里挑灯看剑，梦回吹角连营。</strong> —— 醉酒中挑亮灯芯观看宝剑，梦醒后回到相连接的军营。（辛弃疾《破阵子》）</li></ol><hr><h2 id="唐宋典故" tabindex="-1">唐宋典故 <a class="header-anchor" href="#唐宋典故" aria-label="Permalink to &quot;唐宋典故&quot;">​</a></h2><h3 id="阳关折柳" tabindex="-1">阳关折柳 <a class="header-anchor" href="#阳关折柳" aria-label="Permalink to &quot;阳关折柳&quot;">​</a></h3><p><strong>典故：</strong> 古人送客至渭城，有&quot;客舍青青柳色新&quot;之说，折柳枝相赠以示离别。柳与&quot;留&quot;谐音，表示挽留之意。 <strong>出处：</strong> 王维《送元二使安西》 <strong>释义：</strong> 指友人离别时折柳相送的习俗。</p><h3 id="雪中送炭" tabindex="-1">雪中送炭 <a class="header-anchor" href="#雪中送炭" aria-label="Permalink to &quot;雪中送炭&quot;">​</a></h3><p><strong>典故：</strong> 宋太宗时，有一年天气严寒，大雪纷飞。太宗命人给贫困百姓和军属送去银两和木炭，帮助他们渡寒。 <strong>出处：</strong> 《宋史·太宗本纪》 <strong>释义：</strong> 在别人急需时及时给予帮助。</p><h3 id="梦笔生花" tabindex="-1">梦笔生花 <a class="header-anchor" href="#梦笔生花" aria-label="Permalink to &quot;梦笔生花&quot;">​</a></h3><p><strong>典故：</strong> 传说李白少年时梦见笔头上生出花来，从此文思敏捷，下笔成章。 <strong>出处：</strong> 《开元天宝遗事》 <strong>释义：</strong> 比喻写作能力增强，或才华横溢，文思丰富。</p><h3 id="推敲" tabindex="-1">推敲 <a class="header-anchor" href="#推敲" aria-label="Permalink to &quot;推敲&quot;">​</a></h3><p><strong>典故：</strong> 贾岛在街上想出&quot;鸟宿池边树，僧敲月下门&quot;两句诗，在驴背上反复比较用&quot;推&quot;还是&quot;敲&quot;，冲撞了韩愈的仪仗队。韩愈说：&quot;用&#39;敲&#39;字好。&quot; <strong>出处：</strong> 《刘宾客嘉话录》 <strong>释义：</strong> 比喻做文章或做事时反复琢磨，精心研究。</p><h3 id="囊萤映雪" tabindex="-1">囊萤映雪 <a class="header-anchor" href="#囊萤映雪" aria-label="Permalink to &quot;囊萤映雪&quot;">​</a></h3><p><strong>典故：</strong> 晋代车胤家贫无油点灯，夏季用白色薄纱口袋装萤火虫借光读书；孙康家贫无油点灯，冬天坐在雪地里借雪光映照读书。 <strong>出处：</strong> 《晋书·车胤传》《孙康传》 <strong>释义：</strong> 形容在艰难条件下勤奋读书。</p><hr><h2 id="分类说明" tabindex="-1">分类说明 <a class="header-anchor" href="#分类说明" aria-label="Permalink to &quot;分类说明&quot;">​</a></h2><ul><li><strong>诗</strong> — 古体诗、近体诗，各代名篇佳作</li><li><strong>词</strong> — 婉约与豪放，苏辛李柳，各领风骚</li><li><strong>曲</strong> — 元曲，散曲与杂剧</li><li><strong>赋</strong> — 汉赋、骈文，美文传统</li><li><strong>文</strong> — 古文、时文，名家论说</li></ul><hr><p><em>本文库由 GuoAgent 运营维护</em></p>',25)])])}const q=o(l,[["render",i]]);export{c as __pageData,q as default};
